SELECT COALESCE(SUM(amount), 0) FROM bill
WHERE type = #{type}
  AND bill_date >= #{startTime}
  AND bill_date <= #{endTime}
  AND deleted = 0

SELECT COALESCE(SUM(amount), 0) FROM bill
WHERE category_id = #{categoryId}
  AND bill_date >= #{startTime}
  AND bill_date <= #{endTime}
  AND deleted = 0
